try{
  const raw = $input.first().json.content.parts[0].text;

// Strip the markdown code fences
const cleaned = raw
  .replace(/^```json\n/, '')
  .replace(/\n```$/, '')
  .trim();

const parsed = JSON.parse(cleaned);

return {
  extended_reasoning: parsed.extended_reasoning,
  reasoning_summary: parsed.reasoning_summary,
  score: parsed.score,
  error: null
};
} catch (err){
  return {
  extended_reasoning: null,
  reasoning_summary: null,
  score: 0,
  error: Error
};
}

let category = 'unknown';
try {
  const raw = $input.first().json.text.replace(/```json|```/g, '').trim();
  category = JSON.parse(raw).category;
} catch(e) {}

let from = '', subject = '', body = '';
try { from    = $('Webhook').first().json.from;    } catch(e) {}
try { subject = $('Webhook').first().json.subject; } catch(e) {}
try { body    = $('Webhook').first().json.body;    } catch(e) {}

try { if (!from)    from    = $('Evaluation Dataset').first().json.from_email || $('Evaluation Dataset').first().json.from; } catch(e) {}
try { if (!subject) subject = $('Evaluation Dataset').first().json.subject; } catch(e) {}
try { if (!body)    body    = $('Evaluation Dataset').first().json.body;    } catch(e) {}

return [{ json: { category, from, subject, body } }];
